sparql:
SELECT ?author WHERE {
  ?novel wdt:P144 ?movie .
  ?novel wdt:P1082 ?author .
  ?movie rdfs:label "The Lord of the Rings" @en .
  ?novel rdfs:label "The Lord of the Rings" @en
}

SELECT DISTINCT ?voiceActor WHERE {
  wd:Q98537283 wdt:P725 ?voiceActor .
  ?voiceActor wdt:P31 wd:Q13110753
}

SELECT ?genre WHERE {
  wd:Q108822278 wdt:P136 ?genre
}

SELECT ?item WHERE {
  ?item wdt:P577 ?year .
}

SELECT ?match WHERE {
  ?match wdt:P1945 ?penaltyScore
}

SELECT(COUNT(?film) AS ?count) WHERE {
  ?film wdt:P571 ?releaseYear .
  ?film wdt:P1810 ?series .
  ?series wdtd:P571 wd:Q2716420 .
  FILTER(?releaseYear < '2013-01-01' ^^ xsd:date)
}

SELECT ?appearance WHERE {
  wd:Q152377 wdt:P1350 ?appearance
}

SELECT ?book WHERE {
  wd:Q590252 ?p ?book .
}

SELECT ?publicationDate WHERE {
  wd:Q289130 wdt:P577 ?publicationDate
}

SELECT ?player ?team ?season WHERE {
  ?player wdt:P54 ?team .
  ?team wdt:P5138 ?season .
  ?player wdt:P1351 ?goals
}

SELECT ?player WHERE {
  ?player wdtd:P1532 wd:Q36
}

SELECT ?film WHERE {
  ?film wdt:P1332 ?date .
  ?date wdte:year 2002 .
}

SELECT ?book ?publicationYear WHERE {
  ?book wdt:P577 ?publicationYear .
  FILTER(CONTAINS(str(?book) , 'The Clan of the Cave Bear'))
}

SELECT ?year WHERE {
  wd:Q631 wdt:P2522 wd:Q153585 .
  ?year wdty:yearNumber wd:Q153585
}

SELECT ?character ?relation WHERE {
  ?character wdtp:P1441 wd:Q184222 .
  ?character wdtp:P1441 wd:Q36097 .
}

SELECT ?wife ?father(STR(?title) AS ?title) WHERE {
  ?wife wdt:P26 wd:Q38370 .
  ?wife wdt:P22 ?father .
  ?father rdfs:label ?title .
}

SELECT ?founder(str(?birthDate) AS ?birthDate) WHERE {
  wd:Q19837 wdt:P569 ?birthDate .
}

SELECT ?state WHERE {
  ?state ?p ?o
}

SELECT ?tailor WHERE {
  ?tailor wdt:P31 wd:Q472717 .
  ?tailor wdt:P571 ?date .
  ?date datatypeweb:year ?year .
  FILTER(?year >= 1901 && ?year <= 2000)
}

SELECT ?subject ?country WHERE {
  ?subject wdt:P17 ?country .
  FILTER(?country != wd:Q30)
}

SELECT ?caliphate ?caliph ?occupation WHERE {
  ?caliph wdt:P106 ?occupation .
  ?caliph rdfs:label ?caliph_label .
  ?caliph rdfs:label ?caliph_label .
  FILTER(CONTAINS(STR(?caliph_label) , 'first caliph') || CONTAINS(STR(?caliph_label) , 'Abu Bakr') || CONTAINS(STR(?caliph_label) , 'Muawiya I') || CONTAINS(STR(?caliph_label) , 'Abu al-Abbas as-Saffah') || CONTAINS(STR(?caliph_label) , 'Muhammad al-Fatimid'))
}

SELECT ?actor ?birthdate ?age WHERE {
  ?actor wdt:P569 ?birthdate .
  BIND((YEAR(STRDT(?birthdate , 'ISO8601')) - 1964) AS ?age)
}

SELECT ?country ?countryLabel ?parliament ?parliamentLabel ?seats WHERE {
  ?country wdt:P194 ?parliament .
  ?parliament wdt:P1342 ?seats .
  ?country rdfs:label ?countryLabel .
  ?parliament rdfs:label ?parliamentLabel .
}

SELECT ?occupation WHERE {
  ?person wdt:P106 ?occupation
}

SELECT DISTINCT ?character (rdfs:label AS ?label)
WHERE {
  ?character wdt:P31 wd:Q4205826 .
}
UNION
SELECT DISTINCT ?character (rdfs:label AS ?label)
WHERE {
  ?character wdt:P31 wd:Q4463198 .
}

SELECT ?event WHERE {
  ?event ?p ?o
}

SELECT ?artist ?group WHERE {
  ?artist wdt:P106 ?group .
}

SELECT ?match ?homeTeam WHERE {
  ?match ?p ?homeTeam .
}

SELECT ?match ?club ?margin WHERE {
  ?match ?p ?club .
  ?match ?p ?margin .
}

SELECT ?artist ?birthDate WHERE {
  ?artist wdt:P569 ?birthDate
}

SELECT ?opponent(STR(?color) AS ?color) WHERE {
  ?match wdt:P1923 ?opponent .
  ?opponent wdt:P1082 ?color .
}

SELECT ?team WHERE {
  ?team wdt:P106 ?position .
}

SELECT ?team WHERE {
  ?team wdt:P131 wd:Q4630361
}

SELECT ?player WHERE {
  ?player wdt:P54 wd:Q4574182 .
  ?player wdt:P1050 ?injury .
  ?injury wdwd:P14591 ?kneeSurgery .
  ?injury wdt:P276 wd:Q271880
}

SELECT ?s WHERE {
  ?s ?p ?o
}

SELECT ?player ?birthYear WHERE {
  ?player wdt:P569 ?birthYear .
  FILTER(STR(?birthYear) = '1950')
}

SELECT ?game WHERE {
  ?game ?p ?o
}

SELECT ?event ?lapTime WHERE {
  ?event ?p ?lapTime
}

SELECT ?player ?birthYear WHERE {
  ?player wdt:P569 ?birthYear .
}

SELECT ?time WHERE {
  wd:Q9673 wdtp:Q3_time ?time .
}

SELECT ?game(MAX(?duration) AS ?maxDuration) WHERE {
  ?game wdt:P2047 ?duration .
  ?game wdt:P1923 wd:Q334634 .
  ?game wdt:P1923 wd:Q650840 .
  ?game wdt:P118 wd:Q865526
}
